ASHLAND_A1_DESCRIPTION_MISMATCHES = {
    "liquid_cap_blue_dark": "Tagged as liquid cap but transparent in source; excluded.",
    "liquid_body_blue_dark": "Tagged as liquid body but transparent in source; excluded.",
    "lava_cap": "Tagged as lava cap but transparent in source; excluded.",
    "lava_orb": "Tagged as lava orb but transparent in source; excluded.",
    "lava_body": "Tagged as lava body but transparent in source; excluded.",
}


def _a1_coord_in_curated_feature_band(col: int, row: int) -> bool:
    in_light_band = 0 <= col <= 7 and 0 <= row <= 5
    in_mid_band = 8 <= col <= 11 and 0 <= row <= 5
    return in_light_band or in_mid_band


def _a1_build_border_groups() -> dict[str, tuple[str, ...]]:
    coord_to_group = {
        tuple(entry["coord"]): str(entry["group"]) for entry in ASHLAND_A1_MANIFEST.values()
    }
    borders_by_tile_id: dict[str, tuple[str, ...]] = {}
    for entry in ASHLAND_A1_MANIFEST.values():
        col, row = entry["coord"]
        groups: set[str] = set()
        for d_col, d_row in ((1, 0), (-1, 0), (0, 1), (0, -1)):
            neighbor = coord_to_group.get((col + d_col, row + d_row))
            if neighbor is not None:
                groups.add(neighbor)
        borders_by_tile_id[str(entry["id"])] = tuple(sorted(groups))
    return borders_by_tile_id


ASHLAND_A1_TILE_BORDER_GROUPS = _a1_build_border_groups()

ASHLAND_A1_TILE_STRUCTURE_MEMBERSHIP: dict[str, list[dict[str, object]]] = {}
for _template in ASHLAND_A1_STRUCTURE_TEMPLATES:
    for _cell in _template["cells"]:
        _tile_id = str(_cell["tile_id"])
        ASHLAND_A1_TILE_STRUCTURE_MEMBERSHIP.setdefault(_tile_id, []).append(
            {
                "structure_id": _template["structure_id"],
                "structure_group": _template["structure_group"],
                "structure_role": _cell["structure_role"],
                "footprint": _template["footprint"],
            }
        )

ASHLAND_A1_TILE_SELECTION_FLAGS: dict[str, dict[str, object]] = {}
for _entry in ASHLAND_A1_MANIFEST.values():
    _tile_id = str(_entry["id"])
    _group = str(_entry["group"])
    _col, _row = _entry["coord"]
    _borders_groups = ASHLAND_A1_TILE_BORDER_GROUPS.get(_tile_id, ())
    _memberships = ASHLAND_A1_TILE_STRUCTURE_MEMBERSHIP.get(_tile_id, [])

    _exclude_reasons: list[str] = []
    if _group in ASHLAND_A1_SELECTION_EXCLUDED_GROUPS:
        _exclude_reasons.append("excluded_group")
    if not _a1_coord_in_curated_feature_band(_col, _row):
        _exclude_reasons.append("outside_curated_feature_band")
    if "empty" in _borders_groups:
        _exclude_reasons.append("borders_empty_group")

    ASHLAND_A1_TILE_SELECTION_FLAGS[_tile_id] = {
        "group": _group,
        "group_role": ASHLAND_A1_GROUP_ROLES.get(_group, "unknown"),
        "borders_groups": list(_borders_groups),
        "exclude_from_feature_selection": bool(_exclude_reasons),
        "exclude_reasons": _exclude_reasons,
        "can_place_standalone": False,
        "structure_memberships": _memberships,
        "description_mismatch_note": ASHLAND_A1_DESCRIPTION_MISMATCHES.get(_group),
    }
